// ---------------------------------------------------------------------------
// Assembly: resolve style_guideline + color/flavor/abv/ibu fallbacks, and shape
// every field as { value, source, confidence } (or a bare value for id/name/
// image/notes, which don't carry per-field provenance).
// ---------------------------------------------------------------------------
const out = BEERS_RAW.map((r) => {
	const styleGuideline = r.style ? baGuidelineFor(r.style) : null;
	const key = styleGuideline?.key ?? null;

	let abvField;
	if (r.abv !== null && r.abv !== undefined) {
		abvField = field(r.abv, 'beer-list.xls', 'high');
	} else if (styleGuideline?.abv) {
		abvField = field(avgRange(styleGuideline.abv), 'style_guideline', 'low');
	} else {
		abvField = field(null, null, 'low');
	}

	const ibuField = styleGuideline?.ibu
		? field(avgRange(styleGuideline.ibu), 'style_guideline', 'low')
		: field(null, null, 'low');

	const color = key && STYLE_KEY_COLOR[key] ? STYLE_KEY_COLOR[key] : null;
	const flavor = key && STYLE_KEY_FLAVOR[key] ? STYLE_KEY_FLAVOR[key] : [];

	return {
		id: r.id,
		name: r.name,
		brewery: field(r.brewery, r.brewerySource, r.breweryConfidence),
		style: field(r.style, r.styleSource, r.styleConfidence),
		abv: abvField,
		ibu: ibuField,
		country: field(r.country, r.brewerySource, r.breweryConfidence),
		city: field(r.city, r.brewerySource, r.breweryConfidence),
		color: field(color, key ? 'style_guideline' : null, 'low'),
		flavor: field(flavor, key ? 'style_guideline' : null, 'low'),
		gluten_free: r.glutenFree ? field(true, 'beer-list.xls', 'high') : field(null, null, 'low'),
		vegan: r.vegan ? field(true, 'beer-list.xls', 'high') : field(null, null, 'low'),
		packaging: field(
			r.packaging,
			r.packaging.length ? 'beer-list.xls' : null,
			r.packaging.length ? 'high' : 'low'
		),
		image: r.image,
		image_source: r.imageSource,
		notes: '',
		style_guideline: styleGuideline
	};
});

writeFileSync(OUT, JSON.stringify(out, null, 2));
console.log(`Wrote ${out.length} beers to ${OUT}`);
